export const EMOTES = EMOTE_FAMILIES.flatMap((f) => f.emotes);

const EMOTE_MAP = Object.fromEntries(EMOTES.map((e) => [e.key, e]));

export function emoteByKey(key) {
  if (!key) return null;
  return EMOTE_MAP[key] ?? EMOTE_MAP[`friendly-panda/${key}`] ?? null;
}

export function emoteMessage(key) {
  return `[emote:${key}]`;
}

export function parseEmoteMessage(message) {
  const m = message?.match(/^\[emote:([\w/-]+)\]$/);
  if (!m) return null;
  return emoteByKey(m[1]);
}
